#include "noc_routing_algorithm_creator.h"
#include "xy_routing.h"
#include "bfs_routing.h"
#include "west_first_routing.h"
#include "north_last_routing.h"
#include "negative_first_routing.h"
#include "odd_even_routing.h"
#include "vpr_error.h"

std::unique_ptr<NocRouting> NocRoutingAlgorithmCreator::create_routing_algorithm(const std::string& routing_algorithm_name,
                                                                                 const NocStorage& noc_model) {
    std::unique_ptr<NocRouting> noc_routing_algorithm;

    if (routing_algorithm_name == "xy_routing") {
        noc_routing_algorithm = std::make_unique<XYRouting>();
    } else if (routing_algorithm_name == "bfs_routing") {
        noc_routing_algorithm = std::make_unique<BFSRouting>();
    } else if (routing_algorithm_name == "west_first_routing") {
        noc_routing_algorithm = std::make_unique<WestFirstRouting>();
    } else if (routing_algorithm_name == "north_last_routing") {
        noc_routing_algorithm = std::make_unique<NorthLastRouting>();
    } else if (routing_algorithm_name == "negative_first_routing") {
        noc_routing_algorithm = std::make_unique<NegativeFirstRouting>();
    } else if (routing_algorithm_name == "odd_even_routing") {
        noc_routing_algorithm = std::make_unique<OddEvenRouting>(noc_model);
    } else {
        VPR_FATAL_ERROR(VPR_ERROR_OTHER, "The provided NoC routing algorithm '%s' is not supported.", routing_algorithm_name.c_str());
    }

    return noc_routing_algorithm;
}

#pragma once
/**
 * @file
 * @brief This file defines the NocRouter class.
 *
 * Overview
 * ========
 * The NocRouter represents a physical router in the NoC.
 * The NocRouter acts as nodes in the NoC and is used as
 * entry points to the NoC. The NocRouters are created based
 * on the topology information provided by the user in the arch file.
 *
 * The NocRouter contains the following information:
 * - The router id. This represents the unique ID given by the
 * user in the architecture description file when describing a
 * router. The purpose of this is to help the user identify the
 * router when logging information or displaying errors.
 * - The grid position of the physical router tile this object
 * represents. Each router in the NoC represents a physical router
 * tile in the FPGA device. By storing the grid positions, we can quickly
 * get the corresponding physical router tile information by searching
 * the DeviceGrid in the device context.
 * - The design module (router cluster blocks) currently occupying this tile. Within the user
 * design there will be a number of instantiations of NoC routers. The user
 * will also provide information about which router blocks will be
 * communication with each other. During placement, it is possible for
 * the router blocks to move between the physical router tiles, so
 * by storing the module reference, we can determine which physical router tiles are communicating between each other and find a route
 * between them.
 */

#include "clustered_netlist_fwd.h"
#include "physical_types.h"

class NocRouter {
  private:
    /** This represents a unique id provided by the user when describing the NoC topology in the arch file. The intended
     * use is to report errors with router ids the user understands*/
    int router_user_id;

    // device position of the physical router tile
    /** Represents the horizontal grid position on the device 
     * the physical router tile is located*/
    int router_grid_position_x;
    /** Represents the vertical grid position on the device 
     * the physical router is located*/
    int router_grid_position_y;
    /** Represents the layer number of the die 
     * that the physical router is located*/
    int router_layer_position;

    /** The zero-load latency of this NoC router. */
    double router_latency;

    /** A unique identifier that represents a router block in the 
     * clustered netlist that is placed on the physical router*/
    ClusterBlockId router_block_ref;

  public:
    NocRouter(int id,
              int grid_position_x,
              int grid_position_y,
              int layer_position,
              double latency);

    // getters

    /**
     * @brief Gets the unique id assigned by the user for the physical router
     * @return A numerical value (integer) that represents the physical router id
     */
    int get_router_user_id() const;

    /**
     * @brief Gets the horizontal position on the FPGA device that the physical router is located
     * @return A numerical value (integer) that represents horizontal position of the physical router
     */
    int get_router_grid_position_x() const;

    /**
     * @brief Gets the vertical position on the FPGA device that the physical router is located
     * @return A numerical value (integer) that represents vertical position of the physical router
     */
    int get_router_grid_position_y() const;

    /**
     * @brief Gets the layer number of the die the the physical router is located
     * @return A numerical value (integer) that represents layer position of the physical router
     */
    int get_router_layer_position() const;

    /**
     * @brief Gets the physical location where the the physical router is located
     * @return t_physical_tile_loc that contains x-y coordinates and the layer number
     */
    t_physical_tile_loc get_router_physical_location() const;

    /**
     * @brief Gets the zero-load latency of this NoC router.
     * @return The zero-load latency in seconds.
     */
    double get_latency() const;

    /**
     * @brief Gets the unique id of the router block that is current placed on the physical router
     * @return A ClusterBlockId that identifies a router block in the clustered netlist
     */
    ClusterBlockId get_router_block_ref() const;

    // setters
    /**
     * @brief Sets the router block that is placed on the physical router
     * @param router_block_ref_id A ClusterBlockId that represents a router block
     */
    void set_router_block_ref(ClusterBlockId router_block_ref_id);
};

#pragma once
/**
 * @file
 * @brief This file declares the WestFirstRouting class, which implements
 * the west-first routing algorithm.
 *
 * Overview
 * ========
 * The WestFirstRouting class performs packet routing between routers in the
 * NoC using west-first routing algorithm. In this algorithm, moving towards
 * west has a higher priority than other directions. When the traffic flow
 * moves in directions other than west, it is no longer allowed to move
 * in towards west.
 */

#include "turn_model_routing.h"

class WestFirstRouting : public TurnModelRouting {
  public:
    ~WestFirstRouting() override;

  private:
    /**
     * @brief Returns legal directions that the traffic flow can follow to
     * generate a minimal route using west-first algorithm.
     *
     * @param src_router_id  A unique ID identifying the source NoC router.
     * @param curr_router_id A unique ID identifying the current NoC router.
     * @param dst_router_id  A unique ID identifying the destination NoC router.
     * @param noc_model A model of the NoC. This is used to  determine the position
     * of NoC routers.
     *
     * @return std::vector<TurnModelRouting::Direction> All legal directions that the
     * a traffic flow can follow based on west-first algorithm
     */
    const std::vector<TurnModelRouting::Direction>& get_legal_directions(NocRouterId src_router_id,
                                                                         NocRouterId curr_router_id,
                                                                         NocRouterId dst_router_id,
                                                                         TurnModelRouting::Direction prev_dir,
                                                                         const NocStorage& noc_model) override;

    bool is_turn_legal(const std::array<std::reference_wrapper<const NocRouter>, 3>& noc_routers,
                       const NocStorage& noc_model) const override;
};

#pragma once
/**
 * @file
 * @brief SAT formulation of NoC traffic flow routing.
 *
 * This file implements a SAT formulation of NoC routing problem.
 * Each (traffic flow, link) pair is associated with boolean variable.
 * When one of these boolean variables are set by the SAT solver, it means
 * that the corresponding traffic flow is routed through the corresponding link.
 * To ensure that traffic flow routes are continuous, deadlock-free, with
 * minimum link congestion, several constraints are added to the SAT formulation.
 *
 * For more details refer to the following paper:
 * The Road Less Traveled: Congestion-Aware NoC Placement and Packet Routing for FPGAs
 */

#ifdef ENABLE_NOC_SAT_ROUTING

#include <utility>
#include <map>

#include "noc_data_types.h"
#include "vpr_types.h"
#include "vtr_hash.h"
#include "vtr_vector.h"
#include "clustered_netlist_fwd.h"

/**
 * @brief Assuming that logical NoC routers are fixed,
 * this function formulates routing traffic flows as a SAT
 * problem and tries to find a deadlock-free and congestion-free
 * routing with the minimum aggregate bandwidth while meeting
 * traffic flow latency constraints.
 *
 * @param minimize_aggregate_bandwidth Indicates whether the SAT solver
 * should minimize the aggregate bandwidth or not. A congestion-free
 * and deadlock-free solution can be found faster if the solver does not
 * need to minimize the aggregate bandwidth.
 * @param seed An integer seed to initialize the SAT solver.
 * @return The generated routes for all traffic flows.
 */
vtr::vector<NocTrafficFlowId, std::vector<NocLinkId>> noc_sat_route(bool minimize_aggregate_bandwidth,
                                                                    const t_noc_opts& noc_opts,
                                                                    int seed);

namespace std {

template<>
struct hash<std::pair<NocTrafficFlowId, NocLinkId>> {
    /**
     * @brief Generates a hash value for a (NocTrafficFlowId, NocLinkId) pair.
     *
     * This hash function is used to store SAT boolean variables for each
     * (traffic flow, link) pair in a hash map.
     *
     * @param flow_link A (traffic flow, link) pair whose hash value is desired.
     * @return The computed hash value.
     */
    std::size_t operator()(const std::pair<NocTrafficFlowId, NocLinkId>& flow_link) const noexcept {
        std::size_t seed = std::hash<NocTrafficFlowId>{}(flow_link.first);
        vtr::hash_combine(seed, flow_link.second);
        return seed;
    }
};
} // namespace std

#endif

