53	// setters for the traffic flows
54	
55	void NocTrafficFlows::create_noc_traffic_flow(const std::string& source_router_module_name,
56	                                              const std::string& sink_router_module_name,
57	                                              ClusterBlockId source_router_cluster_id,
58	                                              ClusterBlockId sink_router_cluster_id,
59	                                              double traffic_flow_bandwidth,
60	                                              double traffic_flow_latency,
61	                                              int traffic_flow_priority) {
62	    VTR_ASSERT_MSG(!built_traffic_flows, "NoC traffic flows have already been added, cannot modify further.");
63	
64	    // create and add the new traffic flow to the vector
65	    noc_traffic_flows.emplace_back(source_router_module_name,
66	                                   sink_router_module_name,
67	                                   source_router_cluster_id,
68	                                   sink_router_cluster_id,
69	                                   traffic_flow_bandwidth,
70	                                   traffic_flow_latency,
71	                                   traffic_flow_priority);
72	
73	    //since the new traffic flow was added to the back of the vector, its id will be the index of the last element
74	    NocTrafficFlowId curr_traffic_flow_id = (NocTrafficFlowId)(noc_traffic_flows.size() - 1);
75	    noc_traffic_flows_ids.emplace_back(curr_traffic_flow_id);
76	
77	    // now add the new traffic flow to flows associated with the current source and sink router
78	    add_traffic_flow_to_associated_routers(curr_traffic_flow_id, source_router_cluster_id);
79	    add_traffic_flow_to_associated_routers(curr_traffic_flow_id, sink_router_cluster_id);
80	}
