115	// private functions used internally
116	
117	void NocTrafficFlows::add_traffic_flow_to_associated_routers(NocTrafficFlowId traffic_flow_id, ClusterBlockId associated_router_id) {
118	    // get a reference to the traffic flows associated with the current router
119	    auto router_traffic_flows = traffic_flows_associated_to_router_blocks.find(associated_router_id);
120	
121	    // check if a vector associated traffic flows exists
122	    if (router_traffic_flows == traffic_flows_associated_to_router_blocks.end()) {
123	        // there exists no associated traffic flows for this router, so we add it with the newly created traffic flow id
124	        traffic_flows_associated_to_router_blocks.insert(std::pair<ClusterBlockId, std::vector<NocTrafficFlowId>>(associated_router_id, {traffic_flow_id}));
125	    } else {
126	        // there already is a vector associated of traffic flows for the current router, so add it
127	        router_traffic_flows->second.emplace_back(traffic_flow_id);
128	    }
129	}
