131	void NocTrafficFlows::echo_noc_traffic_flows(char* file_name) {
132	    FILE* fp;
133	    fp = vtr::fopen(file_name, "w");
134	
135	    // file header
136	    fprintf(fp, "----------------------------------------------------------------------------\n");
137	    fprintf(fp, "NoC Traffic Flows\n");
138	    fprintf(fp, "----------------------------------------------------------------------------\n");
139	    fprintf(fp, "\n");
140	
141	    // print all the routers and their properties
142	    fprintf(fp, "List of NoC Traffic Flows:\n");
143	    fprintf(fp, "----------------------------------------------------------------------------\n");
144	    fprintf(fp, "\n");
145	
146	    int traffic_flow_id = 0;
147	
148	    // go through each traffic flow and print its information
149	    for (const auto& traffic_flow : noc_traffic_flows) {
150	        // print the current traffic flows data
151	        fprintf(fp, "Traffic flow ID: %d\n", traffic_flow_id);
152	        fprintf(fp, "Traffic flow source router block name: %s\n", traffic_flow.source_router_module_name.c_str());
153	        fprintf(fp, "Traffic flow source router block cluster ID: %lu\n", (size_t)traffic_flow.source_router_cluster_id);
154	        fprintf(fp, "Traffic flow sink router block name: %s\n", traffic_flow.sink_router_module_name.c_str());
155	        fprintf(fp, "Traffic flow sink router block cluster ID: %lu\n", (size_t)traffic_flow.sink_router_cluster_id);
156	        fprintf(fp, "Traffic flow bandwidth: %f bps\n", traffic_flow.traffic_flow_bandwidth);
157	        fprintf(fp, "Traffic flow latency: %f seconds\n", traffic_flow.max_traffic_flow_latency);
158	
159	        // separate the next link information
160	        fprintf(fp, "\n");
161	
162	        // update the id for the next traffic flow
163	        traffic_flow_id++;
164	    }
165	
166	    // now print the router cluster ids and their associated traffic flow information for router cluster blocks
167	    // The associated traffic flows represent flows where the router block is either a source or destination router
168	    fprintf(fp, "List of all unique router cluster blocks and their associated traffic flows:\n");
169	    fprintf(fp, "----------------------------------------------------------------------------\n");
170	    fprintf(fp, "\n");
171	
172	    // go through each router block cluster and print its associated traffic flows
173	    // we only print out the traffic flow ids
174	    for (const auto& router_traffic_flows : traffic_flows_associated_to_router_blocks) {
175	        // print the current router cluster id
176	        fprintf(fp, "Cluster ID %lu: ", (size_t)router_traffic_flows.first);
177	
178	        // get the vector of associated traffic flows
179	        auto assoc_traffic_flows = &(router_traffic_flows.second);
180	
181	        // now go through the associated traffic flows of the current router and print their ids
182	        for (auto assoc_traffic_flow : *assoc_traffic_flows) {
183	            fprintf(fp, "%lu ", (size_t)assoc_traffic_flow);
184	        }
185	
186	        // separate to the next cluster associated traffic flows information
187	        fprintf(fp, "\n\n");
188	    }
189	
190	    vtr::fclose(fp);
191	}
