7	BFSRouting::~BFSRouting() = default;
8	
9	void BFSRouting::route_flow(NocRouterId src_router_id,
10	                            NocRouterId sink_router_id,
11	                            NocTrafficFlowId /*traffic_flow_id*/,
12	                            std::vector<NocLinkId>& flow_route,
13	                            const NocStorage& noc_model) {
14	    const NocRouter& src_router = noc_model.get_single_noc_router(src_router_id);
15	    const NocRouter& sink_router = noc_model.get_single_noc_router(sink_router_id);
16	
17	    // destroy any previously stored route
18	    flow_route.clear();
19	
20	    /**
21	     * Keeps track of which routers have been reached already
22	     * while traversing the NoC. This variable will help prevent 
23	     * the algorithm from getting stuck visiting routers that
24	     * have already been visited.
25	     * 
26	     */
27	    std::unordered_set<NocRouterId> visited_routers;
28	
29	    /*
30	     * As the routing goes through the NoC, each router visited has a
31	     * corresponding link that was used to reach the router. This
32	     * data structure stores the link that was used to visit each router in
33	     * the NoC.
34	     * Once the destination router has been found. This data structure can be used to
35	     * trace the path back to the source router.
36	     */
37	    std::unordered_map<NocRouterId, NocLinkId> router_parent_link;
38	
39	    std::queue<NocRouterId> routers_to_process;
40	
41	    // indicates whether the routing algorithm found the destination router. If the destination
42	    // router was not found then this means no route exists between the source and destination router.
43	    bool found_sink_router = false;
44	
45	    // Start by processing the source router of the flow
46	    routers_to_process.push(src_router_id);
47	    visited_routers.insert(src_router_id);
48	
49	    //handle case where the source and sink router of the flow are the same
50	    if (src_router_id == sink_router_id) {
51	        found_sink_router = true;
52	    }
53	
54	    // Explore the NoC from the starting router and try to find a path to the destination router
55	    // We finish searching when there are no more routers to process, or we found the destination router
56	    while (!routers_to_process.empty() && !found_sink_router) {
57	        // get the next router to process
58	        NocRouterId processing_router = routers_to_process.front();
59	        routers_to_process.pop();
60	
61	        // get the links leaving the router currently being processed(these represent possible paths to explore in the NoC)
62	        const std::vector<NocLinkId>& outgoing_links = noc_model.get_noc_router_outgoing_links(processing_router);
63	
64	        // go through the outgoing links of the current router and process the sink routers connected to these links
65	        for (auto link : outgoing_links) {
66	            // get the router connected to the current outgoing link
67	            NocRouterId connected_router = noc_model.get_single_noc_link(link).get_sink_router();
68	
69	            // check if we already explored the router we are visiting
70	            if (visited_routers.find(connected_router) == visited_routers.end()) {
71	                // if we are here then this is the first time visiting this router //
72	                // mark this router as visited and add send the router to be processed
73	                visited_routers.insert(connected_router);
74	                routers_to_process.push(connected_router);
75	
76	                // set the parent link of this router (link used to visit the router) as the current outgoing link
77	                router_parent_link.insert(std::pair<NocRouterId, NocLinkId>(connected_router, link));
78	
79	                // check if the router visited is the destination router
80	                if (connected_router == sink_router_id) {
81	                    // mark that the destination router has been found
82	                    found_sink_router = true;
83	                    // no need to process any more routers
84	                    break;
85	                }
86	            }
87	        }
88	    }
89	
90	    // check if the above search found a valid path from the source to the destination
91	    // router.
92	    if (found_sink_router) {
93	        // a legal path was found, so construct it
94	        generate_route(sink_router_id, flow_route, noc_model, router_parent_link);
95	    } else {
96	        // a path was not found so throw an error to the user
97	        VPR_FATAL_ERROR(VPR_ERROR_OTHER,
98	                        "No route could be found from starting router with id:'%d' and the destination router with id:'%d' "
99	                        "using the breadth-first search routing algorithm.",
100	                        src_router.get_router_user_id(),
101	                        sink_router.get_router_user_id());
102	    }
103	}
