105	void BFSRouting::generate_route(NocRouterId start_router_id,
106	                                std::vector<NocLinkId>& flow_route,
107	                                const NocStorage& noc_model,
108	                                const std::unordered_map<NocRouterId, NocLinkId>& router_parent_link) {
109	    // The intermediate router being visited while tracing the path back from the destination router to the starting router in the flow.
110	    // Initially this is set to the router at the end of the path (destination router)
111	    NocRouterId curr_intermediate_router = start_router_id;
112	
113	    // get a reference to the beginning of the vector that stores the found route of the flow
114	    // need this since each link we find in the path will be added to the beginning of the vector
115	    auto route_beginning = flow_route.begin();
116	
117	    // get the parent link of the start router
118	    auto curr_intermediate_router_parent_link = router_parent_link.find(curr_intermediate_router);
